import{_ as t,o,c as a,a3 as r}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"73. Study Leave","description":"","frontmatter":{"title":"73. Study Leave","eba":"Biomedical Engineers 2025-2028","topics":["leave","study-leave","employment","preliminary"]},"headers":[],"relativePath":"ebas/biomedical-engineers/education-pd/73-study-leave.md","filePath":"ebas/biomedical-engineers/education-pd/73-study-leave.md"}'),s={name:"ebas/biomedical-engineers/education-pd/73-study-leave.md"};function n(i,e,p,l,d,u){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="_73-study-leave" tabindex="-1">73. Study Leave <a class="header-anchor" href="#_73-study-leave" aria-label="Permalink to &quot;73. Study Leave&quot;">​</a></h1><p>This clause does not apply to casual Employees.</p><p><strong>73.1</strong> Quantum of paid study leave available</p><p><strong>(a)</strong> Unless otherwise agreed, Employees will be entitled to paid study leave of up to a maximum of 4 hours per week for up to 26 weeks per annum.</p><p><strong>(b)</strong> A part-time Employee will be entitled to study leave on a pro-rata basis.</p><p><strong>(c)</strong> Study leave pursuant to this clause does not accumulate from year to year.</p><p><strong>73.2</strong> When paid study leave available</p><p><strong>(a)</strong> Study leave will be available at the Employer’s discretion. The Employer will not unreasonably refuse a request for study leave provided the leave is for Biomedical Engineering, scientific or health related study appropriate to the Employee’s role.</p><p><strong>(b)</strong> Study leave relevant to the Employee’s duties and classification shall be taken as mutually agreed by, for example, four hours per week, eight hours per fortnight or in blocks of 38 hours.</p><p><strong>(c)</strong> Paid study leave may, where mutually agreed, be used for the purpose of completing online or in-person components of the approved course, including for the purpose of undertaking placement that cannot be provided by their Employer.</p><p><strong>73.3</strong> Application for paid study leave</p><p><strong>(a)</strong> An Employee wishing to take study leave must:</p><p><strong>(i)</strong> apply in writing to the Employer as early as possible prior to the proposed leave date; and</p><p><strong>(ii)</strong> include with this application: <strong>(A)</strong> details of the course and institution in which the Employee is enrolled or proposes to enrol; and <strong>(B)</strong> details of the relevance of the course to the Employee’s employment.</p><p><strong>(b)</strong> The Employee must also notify the Employer of any change to the course or institution (if relevant), provided that if such notice is not given, approval for study leave may be withdrawn by the Employer.</p><p><strong>73.4</strong> Response to application for paid study leave</p><p><strong>(a)</strong> Wherever possible, the Employer must notify the Employee of whether their request for study leave has been approved within seven days of the application being made.</p><p><strong>(b)</strong> In reaching a decision on approval, the Employer may take account of operational requirements and the relevance of the course.</p>',18)])])}const c=t(s,[["render",n]]);export{h as __pageData,c as default};
